const GLOBE_STEP_DEGREES = 4;
const GLOBE_ROTATION_DEGREES_PER_SECOND = 8;

const GEO_NODES = [
  {lon: -122.33, lat: 47.61},
  {lon: -74.01, lat: 40.71},
  {lon: -46.63, lat: -23.55},
  {lon: -0.13, lat: 51.51},
  {lon: 25.28, lat: -33.92},
  {lon: 55.27, lat: 25.2},
  {lon: 72.88, lat: 19.08},
  {lon: 103.82, lat: 1.35},
  {lon: 106.85, lat: -6.21},
  {lon: 121.47, lat: 31.23},
  {lon: 139.69, lat: 35.68},
  {lon: 151.21, lat: -33.87},
] as const;

const GEO_ROUTES = [
  [0, 1], [1, 3], [1, 2], [3, 5], [3, 4], [5, 6],
  [6, 7], [7, 8], [7, 9], [9, 10], [9, 11], [2, 4],
] as const;

const flatGeoPoint = (lon: number, lat: number) => ({
  x: ((lon + 180) / 360) * 1000,
  y: ((90 - lat) / 180) * 500,
});

const CHART_VALUES = [44, 72, 58, 95, 67, 82, 51, 111, 78, 128, 92, 106, 63, 87, 119, 98, 143, 124];
const METRICS = [
  {label: 'NETWORK', target: 94},
  {label: 'COMMERCE', target: 82},
  {label: 'ENERGY', target: 71},
  {label: 'LOGISTICS', target: 64},
  {label: 'MOBILITY', target: 49},
];

const BackgroundMap: React.FC<{frame: number; fps: number}> = ({frame, fps}) => {
  const drift = Math.sin(frame / (fps * 3.8)) * 5;
  const pulse = 0.6 + Math.sin(frame / 24) * 0.25;
  const routeReveal = clamp(frame, fps * 0.65, fps * 5.4);

  return (
    <AbsoluteFill style={{overflow: 'hidden'}}>
      <svg
        viewBox="0 0 1000 500"
        preserveAspectRatio="xMidYMid meet"
        style={{
          position: 'absolute',
          width: 1080,
          height: 540,
          left: 420 + drift,
          top: 157,
          opacity: 0.54,
          filter: 'drop-shadow(0 0 20px rgba(171,10,47,.2))',
        }}
      >
        <defs>
          <linearGradient id="mapWash" x1="0" x2="1">
            <stop offset="0" stopColor="#4b0718" stopOpacity="0.08" />
            <stop offset="0.48" stopColor="#ec1747" stopOpacity="0.36" />
            <stop offset="1" stopColor="#4b0718" stopOpacity="0.08" />
          </linearGradient>
          <pattern id="mapDots" width="4.5" height="4.5" patternUnits="userSpaceOnUse">
            <circle cx="1.1" cy="1.1" r="0.72" fill="#e61846" opacity="0.72" />
          </pattern>
        </defs>

        <path d={FLAT_LAND_PATH} fill="#23040d" opacity="0.56" />
        <path d={FLAT_LAND_PATH} fill="url(#mapDots)" stroke="#c3183d" strokeWidth="0.75" strokeOpacity="0.34" />
        <path d={FLAT_LAND_PATH} fill="url(#mapWash)" opacity="0.42" />

        {GEO_ROUTES.map(([from, to], i) => {
          const a = flatGeoPoint(GEO_NODES[from].lon, GEO_NODES[from].lat);
          const b = flatGeoPoint(GEO_NODES[to].lon, GEO_NODES[to].lat);
          const bend = Math.max(15, Math.abs(b.x - a.x) * 0.08);
          const d = `M${a.x} ${a.y}Q${(a.x + b.x) / 2} ${Math.min(a.y, b.y) - bend} ${b.x} ${b.y}`;
          const stagger = clamp(routeReveal, i * 0.035, 0.42 + i * 0.035);
          return (
            <path
              key={`${from}-${to}`}
              d={d}
              pathLength="1"
              fill="none"
              stroke={i % 4 === 0 ? '#f7a2b5' : '#df1744'}
              strokeWidth={i % 4 === 0 ? 1 : 0.7}
              strokeDasharray="0.012 0.022"
              strokeDashoffset={1 - stagger}
              opacity={0.17 + (i % 3) * 0.04}
            />
          );
        })}

        {GEO_NODES.map((node, i) => {
          const {x, y} = flatGeoPoint(node.lon, node.lat);
          const wave = (frame / fps * (0.26 + i * 0.008)) % 1;
          return (
            <g key={`${node.lon}-${node.lat}`}>
              <circle cx={x} cy={y} r={1.9} fill="#ff718e" opacity={0.42 + pulse * 0.32} />
              <circle cx={x} cy={y} r={3 + wave * 13} fill="none" stroke="#ff1748" strokeWidth="0.75" opacity={(1 - wave) * 0.24} />
            </g>
          );
        })}
      </svg>

      {Array.from({length: 46}).map((_, i) => {
        const x = (i * 293 + 71) % 1920;
        const y = (i * 157 + 43) % 1080;
        const flicker = 0.2 + 0.8 * Math.max(0, Math.sin(frame * 0.035 + i * 1.7));
        return (
          <div
            key={i}
            style={{
              position: 'absolute',
              left: x,
              top: y,
              width: i % 7 === 0 ? 3 : 1,
              height: i % 7 === 0 ? 3 : 1,
              background: i % 5 === 0 ? COLORS.ice : COLORS.hotRed,
              boxShadow: i % 7 === 0 ? `0 0 10px ${COLORS.hotRed}` : undefined,
              opacity: flicker * 0.32,
            }}
          />
        );
      })}
    </AbsoluteFill>
  );
};

const Globe: React.FC<{frame: number; fps: number; reveal: number}> = ({frame, fps, reveal}) => {
  const scanY = 38 + ((frame * 2.2) % 310);
  const breath = 1 + Math.sin(frame / 34) * 0.006;
  const pathPhase = Math.min(
    GLOBE_LAND_PATHS.length - 1,
    ((frame / fps) * GLOBE_ROTATION_DEGREES_PER_SECOND) / GLOBE_STEP_DEGREES,
  );
  const pathIndex = Math.min(GLOBE_LAND_PATHS.length - 2, Math.floor(pathPhase));
  const rawBlend = Math.max(0, Math.min(1, pathPhase - pathIndex));
  const landBlend = Easing.inOut(Easing.quad)(rawBlend);
  const landA = GLOBE_LAND_PATHS[pathIndex];
  const landB = GLOBE_LAND_PATHS[pathIndex + 1];

  return (
    <div
      style={{
        position: 'absolute',
        width: 390,
        height: 390,
        left: 765,
        top: 236,
        opacity: reveal,
        transform: `scale(${(0.82 + reveal * 0.18) * breath})`,
        filter: 'drop-shadow(0 0 28px rgba(255,15,65,0.38))',
      }}
    >
      <svg viewBox="0 0 360 360" width="100%" height="100%">
        <defs>
          <radialGradient id="globeCore" cx="37%" cy="30%" r="74%">
            <stop offset="0" stopColor="#a61536" />
            <stop offset="0.44" stopColor="#5f0718" />
            <stop offset="0.8" stopColor="#21030b" />
            <stop offset="1" stopColor="#060106" />
          </radialGradient>
          <linearGradient id="edgeShade" x1="0" x2="1">
            <stop offset="0" stopColor="#020104" stopOpacity="0.86" />
            <stop offset="0.17" stopColor="#020104" stopOpacity="0.11" />
            <stop offset="0.5" stopColor="#ff1649" stopOpacity="0.03" />
            <stop offset="0.83" stopColor="#020104" stopOpacity="0.14" />
            <stop offset="1" stopColor="#020104" stopOpacity="0.88" />
          </linearGradient>
          <linearGradient id="scanBeam" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0" stopColor="#ff2f5c" stopOpacity="0" />
            <stop offset="0.5" stopColor="#ff6e8d" stopOpacity="0.5" />
            <stop offset="1" stopColor="#ff2f5c" stopOpacity="0" />
          </linearGradient>
          <pattern id="sphereDots" width="5" height="5" patternUnits="userSpaceOnUse">
            <circle cx="1" cy="1" r="0.55" fill="#f21b49" opacity="0.52" />
          </pattern>
          <pattern id="landTexture" width="5" height="5" patternUnits="userSpaceOnUse">
            <circle cx="1.1" cy="1.1" r="0.9" fill="#ffafc0" opacity="0.76" />
            <circle cx="3.8" cy="3.8" r="0.42" fill="#ff587a" opacity="0.52" />
          </pattern>
          <filter id="landGlow" x="-25%" y="-25%" width="150%" height="150%">
            <feGaussianBlur stdDeviation="2.2" result="blur" />
            <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
          </filter>
          <clipPath id="sphereClip">
            <circle cx="180" cy="180" r="154" />
          </clipPath>
        </defs>

        <circle cx="180" cy="180" r="160" fill="#26030b" opacity="0.8" />
        <circle cx="180" cy="180" r="154" fill="url(#globeCore)" />

        <g clipPath="url(#sphereClip)">
          <circle cx="180" cy="180" r="154" fill="url(#sphereDots)" opacity="0.18" />

          <g filter="url(#landGlow)" opacity="0.3">
            <path d={landA} fill="#ff1648" opacity={1 - landBlend} />
            <path d={landB} fill="#ff1648" opacity={landBlend} />
          </g>
          <g>
            <path d={landA} fill="#d71943" stroke="#ff5274" strokeWidth="0.55" opacity={(1 - landBlend) * 0.96} />
            <path d={landB} fill="#d71943" stroke="#ff5274" strokeWidth="0.55" opacity={landBlend * 0.96} />
          </g>
          <g>
            <path d={landA} fill="url(#landTexture)" opacity={(1 - landBlend) * 0.5} />
            <path d={landB} fill="url(#landTexture)" opacity={landBlend * 0.5} />
          </g>

          <path d={GLOBE_GRATICULE_PATH} fill="none" stroke="#ed3158" strokeWidth="0.68" opacity="0.34" />

          <rect x="26" y={scanY} width="308" height="26" fill="url(#scanBeam)" opacity="0.65" />
          <rect x="25" y="25" width="310" height="310" fill="url(#edgeShade)" />
          <path d="M72 112C118 48 235 30 302 116" fill="none" stroke="#ff7997" strokeWidth="5" opacity="0.13" />
        </g>

        <circle cx="180" cy="180" r="154" fill="none" stroke="#ff315c" strokeWidth="1.6" opacity="0.82" />
        <circle cx="180" cy="180" r="160" fill="none" stroke="#f7f3f4" strokeWidth="1" strokeDasharray="2 8" opacity="0.5" />
        <circle cx="180" cy="180" r="166" fill="none" stroke="#ff1748" strokeWidth="1" strokeDasharray="1 13" opacity="0.4" />
        <line x1="180" x2="180" y1="7" y2="353" stroke="#ff5377" strokeWidth="0.7" opacity="0.38" />
        <line x1="7" x2="353" y1="180" y2="180" stroke="#ff5377" strokeWidth="0.7" opacity="0.38" />
      </svg>
    </div>
  );
};

const HudRings: React.FC<{frame: number; fps: number; reveal: number}> = ({frame, fps, reveal}) => {
  const a = frame * 0.32;
  const b = frame * -0.22;
  const c = Math.sin(frame / (fps * 1.2)) * 12;

  return (
    <div
      style={{
        position: 'absolute',
        width: 700,
        height: 700,
        left: 610,
        top: 78,
        opacity: reveal,
        transform: `scale(${0.9 + reveal * 0.1})`,
      }}
    >
      <svg viewBox="0 0 700 700" width="100%" height="100%" style={{overflow: 'visible'}}>
        <defs>
          <filter id="ringGlow" x="-40%" y="-40%" width="180%" height="180%">
            <feGaussianBlur stdDeviation="3.5" result="b" />
            <feMerge><feMergeNode in="b" /><feMergeNode in="SourceGraphic" /></feMerge>
          </filter>
          <linearGradient id="whiteToPink" x1="0" x2="1">
            <stop offset="0" stopColor="#ffffff" />
            <stop offset="1" stopColor="#ff9ab1" />
          </linearGradient>
        </defs>

        <g transform={`rotate(${b + c} 350 350)`}>
          {Array.from({length: 96}).map((_, i) => {
            const major = i % 8 === 0;
            return (
              <line
                key={i}
                x1="350"
                y1={major ? 19 : 27}
                x2="350"
                y2={major ? 38 : 34}
                transform={`rotate(${i * 3.75} 350 350)`}
                stroke={major ? COLORS.ice : COLORS.red}
                strokeWidth={major ? 1.8 : 1}
                opacity={major ? 0.58 : 0.34}
              />
            );
          })}
          <circle cx="350" cy="350" r="318" fill="none" stroke="#d30d38" strokeWidth="1" strokeDasharray="2 10" opacity="0.7" />
        </g>

        <g transform={`rotate(${a - 32} 350 350)`} filter="url(#ringGlow)">
          <circle
            cx="350"
            cy="350"
            r="296"
            pathLength="100"
            fill="none"
            stroke="url(#whiteToPink)"
            strokeWidth="15"
            strokeDasharray="17 6 10 22 8 37"
            strokeLinecap="butt"
          />
        </g>

        <g transform={`rotate(${b + 18} 350 350)`}>
          <circle cx="350" cy="350" r="270" pathLength="100" fill="none" stroke="#b90b31" strokeWidth="7" strokeDasharray="9 2 2 4 15 68" opacity="0.96" />
          <circle cx="350" cy="350" r="257" pathLength="100" fill="none" stroke="#ff4a70" strokeWidth="2" strokeDasharray="1 1.4 18 8 9 62" opacity="0.7" />
        </g>

        <g transform={`rotate(${a * 0.72 + 86} 350 350)`}>
          <circle cx="350" cy="350" r="239" pathLength="100" fill="none" stroke="#f6f1f2" strokeWidth="12" strokeDasharray="13 17 5 8 17 40" opacity="0.94" />
          <circle cx="350" cy="350" r="220" pathLength="100" fill="none" stroke="#ff214e" strokeWidth="4" strokeDasharray="21 5 4 8 8 54" opacity="0.9" />
        </g>

        <g transform={`rotate(${b * 0.75 - 11} 350 350)`}>
          <circle cx="350" cy="350" r="204" pathLength="100" fill="none" stroke="#fff7f8" strokeWidth="2.2" strokeDasharray="0.7 1.25" opacity="0.72" />
          <circle cx="350" cy="350" r="190" pathLength="100" fill="none" stroke="#b80c31" strokeWidth="5" strokeDasharray="6 5 15 18 9 47" opacity="0.84" />
        </g>

        {[0, 90, 180, 270].map((angle) => (
          <g key={angle} transform={`rotate(${angle} 350 350)`}>
            <line x1="350" y1="3" x2="350" y2="47" stroke="#fbf5f6" strokeWidth="1" opacity="0.44" />
            <circle cx="350" cy="52" r="2.6" fill="#ff315b" />
          </g>
        ))}

        <g fill="#d94a68" fontFamily="Arial, sans-serif" fontSize="9" letterSpacing="2" opacity="0.58">
          <text x="333" y="15">000</text>
          <text x="665" y="354">090</text>
          <text x="332" y="695">180</text>
          <text x="7" y="354">270</text>
        </g>
      </svg>
    </div>
  );
};

const Crosshair: React.FC<{reveal: number; frame: number}> = ({reveal, frame}) => {
  const beam = 0.28 + Math.sin(frame / 18) * 0.08;
  return (
    <AbsoluteFill style={{pointerEvents: 'none', opacity: reveal}}>
      <div style={{position: 'absolute', left: 0, right: 0, top: 429, height: 1, background: `linear-gradient(90deg, transparent, rgba(255,255,255,${beam}) 18%, rgba(255,53,94,.5) 50%, rgba(255,255,255,${beam}) 82%, transparent)`}} />
      <div style={{position: 'absolute', top: 0, bottom: 0, left: 959, width: 1, background: `linear-gradient(180deg, transparent, rgba(255,255,255,${beam}) 18%, rgba(255,53,94,.5) 40%, rgba(255,255,255,${beam}) 82%, transparent)`}} />
      <div style={{position: 'absolute', left: 953, top: 423, width: 13, height: 13, border: '1px solid rgba(255,255,255,.5)', transform: 'rotate(45deg)'}} />
    </AbsoluteFill>
  );
};

const BarChart: React.FC<{frame: number; fps: number}> = ({frame, fps}) => {
  const enter = spring({frame: Math.max(0, frame - fps * 0.15), fps, config: {damping: 18, stiffness: 110, mass: 0.8}});
  const lineReveal = linear(frame, fps * 0.45, fps * 7.05);
  const points = CHART_VALUES.map((v, i) => `${34 + i * 28.7},${212 - v * 1.25}`).join(' ');

  return (
    <div
      style={{
        position: 'absolute',
        left: 92,
        top: 718,
        width: 610,
        height: 292,
        opacity: enter,
        transform: `translateY(${(1 - enter) * 24}px)`,
      }}
    >
      <div style={{display: 'flex', alignItems: 'center', gap: 12, marginLeft: 30, marginBottom: 4}}>
        <div style={{width: 26, height: 3, background: COLORS.hotRed, boxShadow: `0 0 12px ${COLORS.hotRed}`}} />
        <div style={{fontFamily: 'Arial, sans-serif', fontSize: 13, fontWeight: 700, letterSpacing: 5, color: COLORS.ice}}>SIGNAL VELOCITY</div>
        <div style={{fontFamily: 'Arial, sans-serif', fontSize: 9, letterSpacing: 2, color: '#b73a56'}}>LIVE / 24H</div>
      </div>

      <svg viewBox="0 0 610 250" width="610" height="250">
        <defs>
          <linearGradient id="chartAccent" x1="0" y1="1" x2="0" y2="0">
            <stop offset="0" stopColor="#76071e" />
            <stop offset="1" stopColor="#ff1748" />
          </linearGradient>
        </defs>
        {[62, 112, 162, 212].map((y) => (
          <line key={y} x1="26" y1={y} x2="595" y2={y} stroke="#8b1731" strokeWidth="1" opacity="0.22" strokeDasharray="2 10" />
        ))}
        <line x1="26" y1="212" x2="595" y2="212" stroke="#d4163b" strokeWidth="1.2" opacity="0.62" />

        {CHART_VALUES.map((value, i) => {
          const p = spring({frame: Math.max(0, frame - (fps * 0.28 + i * 22)), fps, config: {damping: 18, stiffness: 110, mass: 0.7}});
          if (p <= 0.0001) {
            return null;
          }
          const h = value * 1.25 * p;
          return (
            <g key={i}>
              <rect x={25 + i * 28.7} y={212 - h} width="14" height={h} fill={i > 13 ? '#e7a5b5' : i % 4 === 0 ? '#ef1748' : '#b90a30'} opacity={0.92} />
              <rect x={25 + i * 28.7} y={212 - h} width="14" height="2" fill="#fff" opacity={i > 13 ? 0.8 : 0.28} />
            </g>
          );
        })}

        <polyline points={points} fill="none" stroke="#ff1d4d" strokeWidth="2.2" strokeLinejoin="round" strokeDasharray="1000" strokeDashoffset={1000 * (1 - lineReveal)} />
        {CHART_VALUES.map((value, i) => i % 3 === 2 && (
          <circle key={i} cx={34 + i * 28.7} cy={212 - value * 1.25} r="3" fill="#fff" opacity={lineReveal} />
        ))}

        {['00', '04', '08', '12', '16', '20', '24'].map((label, i) => (
          <text key={label} x={26 + i * 91} y="234" fill="#a43b52" fontSize="9" fontFamily="Arial" letterSpacing="1.5">{label}</text>
        ))}
      </svg>
    </div>
  );
};

const MetricBars: React.FC<{frame: number; fps: number}> = ({frame, fps}) => {
  const enter = spring({frame: Math.max(0, frame - fps * 3.05), fps, config: {damping: 17, stiffness: 90, mass: 0.9}});
  const starts = [3.6, 4.56, 5.86, 7.27, 8.21];
  const ends = [11.45, 12.35, 13.1, 13.85, 14.35];

  return (
    <div
      style={{
        position: 'absolute',
        right: 94,
        top: 718,
        width: 570,
        height: 300,
        opacity: enter,
        transform: `translateX(${(1 - enter) * 46}px)`,
        fontFamily: 'Arial, sans-serif',
      }}
    >
      <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: 22}}>
        <div>
          <div style={{color: COLORS.ice, fontSize: 31, fontWeight: 300, letterSpacing: 8}}>GLOBAL FLOW</div>
          <div style={{color: '#9f304a', fontSize: 9, letterSpacing: 4, marginTop: 4}}>DISTRIBUTED DATA INDEX</div>
        </div>
        <div style={{color: COLORS.hotRed, fontSize: 10, letterSpacing: 3, paddingBottom: 5}}>SYNCHRONIZED</div>
      </div>

      {METRICS.map((metric, i) => {
        const p = linear(frame, fps * starts[i], fps * ends[i]);
        const displayed = Math.round(metric.target * p);
        return (
          <div key={metric.label} style={{height: 42, display: 'grid', gridTemplateColumns: '102px 1fr 53px', gap: 12, alignItems: 'center'}}>
            <div style={{fontSize: 9, color: i === 0 ? COLORS.ice : '#bd5269', letterSpacing: 2.2}}>{metric.label}</div>
            <div style={{height: 10, position: 'relative', background: 'rgba(122,6,29,.34)', borderLeft: '2px solid rgba(255,50,90,.55)'}}>
              <div style={{position: 'absolute', inset: 0, width: `${metric.target * p}%`, background: i === 0 ? 'linear-gradient(90deg,#f42251,#fff6f7)' : 'linear-gradient(90deg,#a20829,#ff5478)', boxShadow: i < 2 ? '0 0 13px rgba(255,29,76,.32)' : undefined}} />
              {Array.from({length: 9}).map((_, j) => (
                <div key={j} style={{position: 'absolute', left: `${(j + 1) * 10}%`, top: 0, height: '100%', width: 1, background: 'rgba(4,3,7,.28)'}} />
              ))}
            </div>
            <div style={{fontSize: 13, color: i === 0 ? '#fff' : '#ff7994', letterSpacing: 2, textAlign: 'right'}}>{displayed.toString().padStart(2, '0')}%</div>
          </div>
        );
      })}
    </div>
  );
};

const MicroInterface: React.FC<{frame: number; fps: number; reveal: number}> = ({frame, fps, reveal}) => {
  const sweep = ((frame / fps) * 38) % 100;
  const packet = Math.floor(frame / 6) % 9999;
  return (
    <AbsoluteFill style={{opacity: reveal, fontFamily: 'Arial, sans-serif', pointerEvents: 'none'}}>
      <div style={{position: 'absolute', left: 78, top: 58, width: 360}}>
        <div style={{display: 'flex', alignItems: 'center', gap: 12}}>
          <div style={{width: 8, height: 8, borderRadius: 8, background: COLORS.hotRed, boxShadow: `0 0 14px ${COLORS.hotRed}`}} />
          <div style={{fontSize: 11, color: COLORS.ice, letterSpacing: 4}}>PLANETARY TELEMETRY</div>
        </div>
        <div style={{marginTop: 13, width: 330, height: 1, background: 'linear-gradient(90deg,#ff1748,rgba(255,23,72,0))'}} />
        <div style={{display: 'flex', gap: 24, marginTop: 10, color: '#a0374f', fontSize: 9, letterSpacing: 2}}>
          <span>LAT 06.2S</span><span>LON 106.8E</span><span>NODE 047</span>
        </div>
      </div>

      <div style={{position: 'absolute', right: 78, top: 58, textAlign: 'right'}}>
        <div style={{fontSize: 10, color: '#b34159', letterSpacing: 3}}>STREAM / PACKET</div>
        <div style={{fontSize: 27, color: COLORS.ice, fontWeight: 300, letterSpacing: 5, marginTop: 5}}>{packet.toString().padStart(4, '0')}</div>
        <div style={{marginTop: 7, width: 220, height: 3, background: 'rgba(110,10,30,.5)', position: 'relative'}}>
          <div style={{height: '100%', width: `${sweep}%`, background: COLORS.hotRed, boxShadow: `0 0 10px ${COLORS.hotRed}`}} />
        </div>
      </div>

      <div style={{position: 'absolute', left: 80, top: 408, display: 'flex', alignItems: 'center', gap: 8}}>
        <div style={{height: 1, width: 225, background: 'linear-gradient(90deg,transparent,#7c1730)'}} />
        <div style={{color: '#a63a52', fontSize: 8, letterSpacing: 3}}>AXIS / X-09</div>
      </div>
      <div style={{position: 'absolute', right: 80, top: 408, display: 'flex', alignItems: 'center', gap: 8}}>
        <div style={{color: '#a63a52', fontSize: 8, letterSpacing: 3}}>LOCKED / 99.97</div>
        <div style={{height: 1, width: 225, background: 'linear-gradient(90deg,#7c1730,transparent)'}} />
      </div>

      {Array.from({length: 18}).map((_, i) => (
        <div key={i} style={{position: 'absolute', left: 44 + i * 104, bottom: 30, width: 1, height: i % 3 === 0 ? 16 : 8, background: i % 6 === 0 ? '#e4204b' : '#581225', opacity: 0.55}} />
      ))}
    </AbsoluteFill>
  );
};

export const Motion: React.FC = () => {
  const frame = useCurrentFrame();
  const {fps} = useVideoConfig();

  const intro = clamp(frame, 0, fps * 1.15);
  const ringReveal = clamp(frame, fps * 0.35, fps * 2.15);
  const mapReveal = clamp(frame, fps * 0.15, fps * 1.8);
  const outro = interpolate(frame, [fps * 14.65, fps * 15], [1, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: Easing.inOut(Easing.quad),
  });
  const globalOpacity = intro * outro;
  const zoom = interpolate(frame, [0, fps * 15], [1.035, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });
  const redBreath = 0.72 + Math.sin(frame / 42) * 0.12;

  return (
    <AbsoluteFill
      style={{
        backgroundColor: COLORS.black,
        overflow: 'hidden',
        color: COLORS.ice,
        opacity: globalOpacity,
      }}
    >
      <AbsoluteFill
        style={{
          transform: `scale(${zoom})`,
          transformOrigin: '50% 42%',
          background: `radial-gradient(circle at 50% 40%, rgba(111,4,27,${redBreath}) 0%, rgba(34,3,12,.5) 18%, rgba(3,3,7,0) 48%), linear-gradient(180deg,#030307 0%,#080208 52%,#020205 100%)`,
        }}
      >
        <BackgroundMap frame={frame} fps={fps} />

        <div style={{position: 'absolute', left: 370, top: 415, width: 1180, height: 32, background: 'linear-gradient(90deg,transparent,rgba(255,10,57,.16),rgba(255,255,255,.09),rgba(255,10,57,.16),transparent)', filter: 'blur(14px)', opacity: ringReveal}} />
        <div style={{position: 'absolute', left: 960, top: 125, width: 1, height: 625, background: 'linear-gradient(180deg,transparent,rgba(255,33,78,.38),transparent)', boxShadow: '0 0 18px rgba(255,33,78,.22)', opacity: ringReveal}} />

        <Crosshair reveal={mapReveal * 0.72} frame={frame} />
        <Globe frame={frame} fps={fps} reveal={ringReveal} />
        <HudRings frame={frame} fps={fps} reveal={ringReveal} />
        <BarChart frame={frame} fps={fps} />
        <MetricBars frame={frame} fps={fps} />
        <MicroInterface frame={frame} fps={fps} reveal={mapReveal} />

        <AbsoluteFill
          style={{
            background: 'repeating-linear-gradient(180deg,rgba(255,255,255,.018) 0px,rgba(255,255,255,.018) 1px,transparent 1px,transparent 4px)',
            mixBlendMode: 'screen',
            opacity: 0.58,
            pointerEvents: 'none',
          }}
        />
        <AbsoluteFill
          style={{
            background: 'radial-gradient(ellipse at center,transparent 42%,rgba(0,0,0,.42) 74%,rgba(0,0,0,.92) 100%)',
            pointerEvents: 'none',
          }}
        />
      </AbsoluteFill>
    </AbsoluteFill>
  );
};
